#!/bin/bash
# Fight CEM (57-dim) on the DEPLOYMENT MIX (50% melee/50% random) with the new Rapid Charge feature [w56],
# seeded from BESTMIX+[0] so it holds the champion and tunes the charge weight + melee fight on our distribution.
cd ~/hoc-common || exit 1
ST=~/hoc-common/rl_state; mkdir -p "$ST"
MEAN='[1.4988647158738944,-0.5910087272415239,0.2097601006630517,1.7452804854334238,2.16542605693082,5.743403823992855,1.602189424260613,0.6855127959862942,-1.7480291327672626,1.4620468328764753,0.38001139143097323,2.5409750188308164,3.124719724241719,1.6320770892411578,-0.030107250290171146,1.8681607730679253,4.096705760150673,5.572435627215912,-1.149135731477136,0.22806599275532963,-1.3582679156796398,1.3998191818966608,-2.0543741522611674,-2.125410620764743,-1.090570653158559,2.2486218345190974,-0.018287685456403264,0.4211808557043179,1.0878744716707025,-0.7826234799203378,-0.6060920991254477,0.5107951707643916,-1.824425650872599,2.695331079711184,-0.9652375927102732,0.7054122954412628,-0.42704814554939513,2.2716833937408287,-0.09902588985700955,-0.4870612969172853,4.333268254490518,2.1266469039736355,-0.8708994895616353,0.7812127211154111,0.397233221968303,0.5054064078311156,1.951625586424147,-0.7168503825154638,1.4148114632296496,0.24884470489427854,-2.753057668341909,0.3892462431626682,0.7293253574050823,0.3358745432824668,0.26720797483195136,1.0411928379179989,0]'
i=0
while true; do
  i=$((i+1)); SEED=$((940000 + i*911))
  echo "=== $(date -u +%H:%M:%S) fightrc iter $i seed $SEED START ===" >> "$ST/fightrc_keepalive.log"
  FIGHT_MELEE_ROSTERS=0.5 OPT_VERSION=v0.6 BASE_VERSION=v0.4 OPT_WEIGHTS_ENV=V06_WEIGHTS \
    CEM_MEAN="$MEAN" CEM_DIM=57 CEM_HOURS=6 CEM_CORES=40 CEM_BATCH=8 \
    CEM_POP=40 CEM_ELITE=8 CEM_GAMES=3000 CEM_VAL_GAMES=2500 CEM_SEED=$SEED \
    CEM_VAL_SEEDS="$((SEED+11)),$((SEED+17)),$((SEED+19)),$((SEED+23)),$((SEED+29))" \
    bun src/simulation/optimizer/cem.mjs >> "$ST/fightrc_keepalive.log" 2>&1
  [ -f sim-out/cem/best.json ] && cp sim-out/cem/best.json "$ST/fightrc_best_iter_$i.json"
  echo "=== $(date -u +%H:%M:%S) fightrc iter $i DONE ===" >> "$ST/fightrc_keepalive.log"
done
